mapper.select:
SELECT j.id, j.employer_account, j.job_description, j.salary_min, j.salary_max, j.work_location, j.university_name, j.latitude, j.longitude, e.company_name FROM job j LEFT JOIN employer e ON j.employer_account = e.employer_account
AND j.employer_account = #{employerAccount}
AND j.status = 1
AND j.university_name = #{universityName}
AND (j.university_name IS NULL OR j.university_name = '')
ORDER BY j.update_time DESC

SELECT j.id, j.employer_account, j.job_description, j.salary_min, j.salary_max, j.work_location, j.university_name, j.latitude, j.longitude, e.company_name FROM job j LEFT JOIN employer e ON j.employer_account = e.employer_account
AND j.employer_account = #{employerAccount}
ORDER BY j.update_time DESC
